						["custom"] = "function(allstates, event, unit)\n       if event == \"UNIT_AURA\" and unit ~= \"player\" then\n           return false\n       end\n\n       local HEAT_SPELL_ID = 807389\n       local EMBER_SPELL_ID = 807533\n\n       local heatStacks = 0\n       local emberStacks = 0\n\n       for i = 1, 40 do\n           local name, rank, icon, count, debuffType, duration, expirationTime, source, isStealable, shouldConsolidate,\n spellId =\n               UnitDebuff(\"player\", i)\n\n           if not name then\n               break\n           end\n\n           if spellId == HEAT_SPELL_ID then\n               heatStacks = tonumber(count) or 0\n           elseif spellId == EMBER_SPELL_ID then\n               emberStacks = tonumber(count) or 0\n           end\n       end\n\n       local value = heatStacks\n\n       if emberStacks >= 5 then\n           value = 100\n       end\n\n       allstates[\"\"] = {\n           show = true,\n           changed = true,\n           progressType = \"static\",\n           value = value,\n           total = 100,\n           stacks = heatStacks,\n           emberStacks = emberStacks,\n           name = \"Heat\",\n       }\n\n       return true\n   end",
